import React from 'react';
import { BrowserRouter, Routes, Route, NavLink } from 'react-router-dom';
import LeadsPage from './pages/LeadsPage';
import MonitorPage from './pages/MonitorPage';
import BotPage from './pages/BotPage';
import SendPage from './pages/SendPage';

interface NavItem {
  to: string;
  label: string;
  end?: boolean;
  icon: React.ReactElement;
}

function IconLeads(): React.ReactElement {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
      <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
      <circle cx="9" cy="7" r="4" />
      <path d="M23 21v-2a4 4 0 0 0-3-3.87" />
      <path d="M16 3.13a4 4 0 0 1 0 7.75" />
    </svg>
  );
}

function IconMonitor(): React.ReactElement {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="22 12 18 12 15 21 9 3 6 12 2 12" />
    </svg>
  );
}

function IconBot(): React.ReactElement {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="11" width="18" height="10" rx="2" />
      <circle cx="12" cy="5" r="2" />
      <path d="M12 7v4" />
      <line x1="8" y1="16" x2="8" y2="16" />
      <line x1="16" y1="16" x2="16" y2="16" />
    </svg>
  );
}

function IconSend(): React.ReactElement {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
      <line x1="22" y1="2" x2="11" y2="13" />
      <polygon points="22 2 15 22 11 13 2 9 22 2" />
    </svg>
  );
}

function IconBrand(): React.ReactElement {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" />
    </svg>
  );
}

const nav: NavItem[] = [
  { to: '/', label: 'Leads', end: true, icon: <IconLeads /> },
  { to: '/monitor', label: 'Monitoring', icon: <IconMonitor /> },
  { to: '/bot', label: 'Bot Engine', icon: <IconBot /> },
  { to: '/send', label: 'Envoi', icon: <IconSend /> },
];

export default function App(): React.ReactElement {
  return (
    <BrowserRouter>
      <div className="min-h-screen flex bg-zinc-950 text-zinc-100">
        {/* Left Sidebar */}
        <aside className="w-52 fixed top-0 left-0 h-screen flex flex-col border-r border-zinc-800 bg-zinc-950 z-10">
          {/* Brand */}
          <div className="px-4 py-5 flex items-center gap-2.5 border-b border-zinc-800">
            <div className="w-7 h-7 rounded-md bg-indigo-600 flex items-center justify-center text-white">
              <IconBrand />
            </div>
            <span className="text-sm font-semibold tracking-tight text-zinc-100">Lead Bot</span>
          </div>

          {/* Nav */}
          <nav className="flex-1 px-2 py-3 space-y-0.5">
            {nav.map(({ to, label, end, icon }) => (
              <NavLink
                key={to}
                to={to}
                end={end}
                className={({ isActive }: { isActive: boolean }) =>
                  `flex items-center gap-2.5 px-3 py-2 rounded-md text-xs font-medium transition-colors ${
                    isActive
                      ? 'bg-indigo-600/15 text-indigo-400'
                      : 'text-zinc-400 hover:text-zinc-100 hover:bg-zinc-800/60'
                  }`
                }
              >
                {({ isActive }: { isActive: boolean }) => (
                  <>
                    <span className={isActive ? 'text-indigo-400' : 'text-zinc-500'}>{icon}</span>
                    {label}
                  </>
                )}
              </NavLink>
            ))}
          </nav>

          {/* Footer */}
          <div className="px-4 py-4 border-t border-zinc-800">
            <p className="text-xs text-zinc-600">v1.0.0</p>
          </div>
        </aside>

        {/* Main content */}
        <main className="ml-52 flex-1 min-h-screen bg-zinc-950">
          <Routes>
            <Route path="/" element={<LeadsPage />} />
            <Route path="/monitor" element={<MonitorPage />} />
            <Route path="/bot" element={<BotPage />} />
            <Route path="/send" element={<SendPage />} />
          </Routes>
        </main>
      </div>
    </BrowserRouter>
  );
}
